        var snapshot = try await store.load()
        if let index = snapshot.runs.firstIndex(where: { $0.id == run.id }) {
            snapshot.runs[index] = run
        } else {
            snapshot.runs.append(run)
        }
        try await store.save(snapshot)
    }

